'use strict';

/**
 * ANL-1 step 6 — refresh docs/FEATURE_KPI_MATRIX.md with MEASURED usage.
 *
 * Reads usage_daily (last 30 days) and rewrites the auto-generated
 * "## Measured usage" section at the end of the matrix doc. Scope-maturity
 * Growth % estimates in the tables stay human-owned; this section is the
 * data-driven view the owner asked for (runs monthly, or on demand):
 *
 *   node scripts/update-kpi-matrix.js            # requires DATABASE_URL
 *
 * Exits 0 on success, 1 when analytics is disabled or the query fails.
 */

const fs = require('fs');
const path = require('path');
const postgresPool = require('../src/db/postgresPool');

const DOC = path.join(__dirname, '../docs/FEATURE_KPI_MATRIX.md');
const MARKER = '<!-- ANL-1:MEASURED-USAGE -->';

function pct(a, b) { return b ? Math.round((a / b) * 100) : 0; }

/** Render the auto section from usage_daily rows. Exported for tests. */
function renderSection(rows, asOf = new Date().toISOString().slice(0, 10)) {
  const lines = [
    MARKER,
    '## Measured usage — last 30 days (auto-generated by scripts/update-kpi-matrix.js)',
    '',
    `_Updated ${asOf} from the usage_daily rollups. Do not edit by hand — rerun the script._`,
    '',
    '| Feature | Starts | Completions | Abandons | Friction % | Median steps | Median secs |',
    '|---|---|---|---|---|---|---|',
  ];
  for (const r of rows) {
    const fr = pct(r.abandons, r.starts);
    const secs = r.p50_duration_ms == null ? '—' : Math.round(r.p50_duration_ms / 1000);
    lines.push(`| ${r.feature} | ${r.starts} | ${r.completions} | ${r.abandons} | ${fr}% | ${r.p50_steps ?? '—'} | ${secs} |`);
  }
  if (!rows.length) lines.push('| _no data yet_ | | | | | | |');
  return lines.join('\n') + '\n';
}

/** Replace (or append) the auto section in the doc text. Exported for tests. */
function spliceDoc(docText, section) {
  const idx = docText.indexOf(MARKER);
  const base = idx === -1 ? docText.replace(/\s*$/, '\n\n') : docText.slice(0, idx);
  return base + section;
}

async function main() {
  if (!postgresPool.isEnabled()) {
    console.error('update-kpi-matrix: DATABASE_URL not set — nothing to read.');
    process.exit(1);
  }
  const res = await postgresPool.query(
    `SELECT feature,
            SUM(starts)::int AS starts,
            SUM(completions)::int AS completions,
            SUM(abandons)::int AS abandons,
            (percentile_cont(0.5) WITHIN GROUP (ORDER BY p50_duration_ms) FILTER (WHERE p50_duration_ms IS NOT NULL))::int AS p50_duration_ms,
            (percentile_cont(0.5) WITHIN GROUP (ORDER BY p50_steps) FILTER (WHERE p50_steps IS NOT NULL))::int AS p50_steps
     FROM usage_daily
     WHERE role = '*' AND day >= CURRENT_DATE - 30
     GROUP BY feature ORDER BY starts DESC`,
  );
  const doc = fs.readFileSync(DOC, 'utf8');
  fs.writeFileSync(DOC, spliceDoc(doc, renderSection(res.rows || [])));
  console.log(`update-kpi-matrix: wrote ${res.rows.length} feature rows into ${path.relative(process.cwd(), DOC)}`);
  await postgresPool.close();
}

if (require.main === module) {
  main().catch((e) => { console.error(`update-kpi-matrix failed: ${e.message}`); process.exit(1); });
}

module.exports = { _internals: { renderSection, spliceDoc, MARKER } };
